import type { ScoreResult } from '../types';
import { invokeJudge } from './llmJudge';

export async function scoreTableHandling(input: string, output: string): Promise<ScoreResult> {
  const prompt = `You are an expert Contentful Data Architect evaluating an ETL pipeline.
Evaluate how an AI agent handled Markdown tables during extraction.

### INPUT PROVIDED TO THE AGENT (Markdown + Schema Definitions):
${input}

### ACTUAL OUTPUT GENERATED BY THE AGENT (Contentful JSON):
${output}

### EVALUATION CRITERION:
**Table Handling:** Did the agent correctly distinguish between:
- Tabular data tables (which should be mapped by headers to specific fields to create new entries)
- Presentational tables (which should be kept as standard rich text)

If the document contains no tables, return score 1.0.

Return ONLY valid JSON in this exact format (no markdown fences, no extra text):
{"score": <number 0.0–1.0>, "reason": "<1–2 sentences, noting any improperly handled tables>"}`;

  try {
    const { score, reason } = await invokeJudge(prompt);
    return { scorerId: 'table-handling', score, reason };
  } catch (err) {
    return { scorerId: 'table-handling', score: -1, reason: `Judge error: ${String(err)}` };
  }
}
